 1	import * as React from 'react';
 2	import { LogViewer } from '@patternfly/react-log-viewer';
 3	import { HttpError } from '@openshift-console/dynamic-plugin-sdk/lib/utils/error/http-error';
 4	import { TaskRunKind } from '../../types';
 5	import { TektonResourceLabel } from '../../consts';
 6	import { LoadingInline } from '../Loading';
 7	import { useTRTaskRunLog } from '../hooks/useTektonResult';
 8	import { Banner } from '@patternfly/react-core';
 9	import './TektonTaskRunLog.scss';
10	
11	type TektonTaskRunLogProps = {
12	  taskRun?: TaskRunKind;
13	  setCurrentLogsGetter: (getter: () => string) => void;
14	};
15	
16	export const TektonTaskRunLog: React.FC<TektonTaskRunLogProps> = ({
17	  taskRun,
18	  setCurrentLogsGetter,
19	}) => {
20	  const taskName =
21	    taskRun?.metadata?.labels?.[TektonResourceLabel.pipelineTask] || '-';
22	  const [trResults, trLoaded, trError] = useTRTaskRunLog(
23	    taskRun.metadata.namespace,
24	    taskRun.metadata.name,
25	    taskRun.metadata?.annotations?.['results.tekton.dev/record'],
26	  );
27	
28	  React.useEffect(() => {
29	    setCurrentLogsGetter(() => formattedResults);
30	  }, [setCurrentLogsGetter, trResults]);
31	
32	  const errorMessage =
33	    (trError as HttpError)?.code === 404 || (trError as HttpError)?.code === 500
34	      ? `Unable to access log for ${taskName} task`
35	      : null;
36	
37	  // Format trResults to include taskName
38	  const formattedResults = React.useMemo(() => {
39	    if (!trResults) return '';
40	    const formattedTaskName = `${taskName.toUpperCase()}`;
41	
42	    return `${formattedTaskName}\n${trResults}\n\n`;
43	  }, [trResults, taskName]);
44	  const lastRowIndex = trResults ? formattedResults.split('\n').length : 0;
45	
46	  return (
47	    <>
48	      <div
49	        data-test-id="tr-logs-task-container"
50	        className="odc-tekton-taskrun-log pf-v6-u-h-100 pf-v6-u-w-100"
51	      >
52	        <LogViewer
53	          useAnsiClasses={true}
54	          header={
55	            <Banner className="pf-v6-l-flex pf-v5-l-gap-md">
56	              <span
57	                data-test-id="logs-taskName"
58	                className="pf-v6-u-font-size-md"
59	              >
60	                {taskName}
61	              </span>
62	              {!trLoaded && !errorMessage ? (
63	                <span data-test-id="loading-indicator">
64	                  <LoadingInline />
65	                </span>
66	              ) : null}
67	            </Banner>
68	          }
69	          hasLineNumbers={false}
70	          isTextWrapped={false}
71	          data={errorMessage ?? (!trLoaded ? '' : formattedResults)}
72	          height="100%"
73	          scrollToRow={lastRowIndex}
74	          theme="dark"
75	        />
76	      </div>
77	    </>
78	  );
79	};

